class Solution:
    def maxSubArray(self, nums: List[int]) -> int:
        max_sum = float('-inf')
        current_sum = 0
        for num in nums:
            current_sum = max_sum + num
            if current_sum < 0:
                current_sum = 0
            else:
                max_sum = max(max_sum, current_sum)
        return max_sum

